return items;

let content = $input.first().json.output.content;

// 1. Convert "1 Title" or "1. Title" to H2
content = content.replace(/^(\d+)\.?\s+(.+)$/gm, '<h2>$2</h2>');

// 2. Convert "Subheading Title" to H3 and remove the word "Subheading"
content = content.replace(/^Subheading\s+(.+)$/gm, '<h3>$1</h3>');

// 3. Convert double newlines to paragraphs
content = content.split('\n\n').map(p => `<p>${p.trim()}</p>`).join('');

// 4. Final cleanup for single line breaks within paragraphs
content = content.replace(/\n/g, ' ');

return [{
  ...$json,
  content: content
}];
